package com.hospital.management.util;import java.sql.*;import java.time.Year;/** Generates collision-safe bill numbers from an Oracle sequence. */public class BillNumberGenerator{public String next(Connection c)throws SQLException{return"BILL-"+Year.now().getValue()+"-"+String.format("%06d",nextValue(c,"BILL_NUMBER_SEQ"));}static long nextValue(Connection c,String sequence)throws SQLException{try(PreparedStatement s=c.prepareStatement("SELECT "+sequence+".NEXTVAL FROM DUAL");ResultSet r=s.executeQuery()){if(!r.next())throw new SQLException("Sequence did not return a value");return r.getLong(1);}}}
